import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// BeehiveWatch is a public-read Utah legislation tracker: browse/detail/conflicts views are
// reachable without auth; a single `editor` role reaches the create/edit form routes.
//
// DEEP-LINKABLE STATE — list filters live in query params (restored on load):
//   • bills:        ?session=&status=&sector=&q=
//   • legislators:  ?chamber=&party=&q=
// Editor sub-actions (add sponsor / set votes / add interest) open via `?modal=` on detail routes.
export const routes: Routes = ([
  { path: '', redirectTo: 'bills', pathMatch: 'full' },

  {
    path: '',
    loadComponent: () => import('./shared/layout.component').then((m) => m.LayoutComponent),
    children: [
      // ---- Bills (public) ----
      {
        path: 'bills',
        loadComponent: () =>
          import('./pages/bills-list/bills-list.component').then((m) => m.BillsListComponent),
        data: {
          flow: {
            flowId: 'bills',
            node: 'bills',
            showInNavbar: true,
            label: 'Bills',
            scope: 'all',
            edgesTo: ['bill-detail', 'bill-new', 'legislators', 'conflicts'],
          },
        },
      },
      {
        path: 'bills/new',
        loadComponent: () =>
          import('./pages/bill-form/bill-form.component').then((m) => m.BillFormComponent),
        canActivate: [authGuard],
        data: {
          flow: { flowId: 'bill-new', node: 'bill-new', label: 'New bill', scope: 'editor', edgesTo: ['bills'] },
        },
      },
      {
        path: 'bills/:id/edit',
        loadComponent: () =>
          import('./pages/bill-form/bill-form.component').then((m) => m.BillFormComponent),
        canActivate: [authGuard],
        data: {
          flow: {
            flowId: 'bill-edit',
            node: 'bill-edit',
            label: 'Edit bill',
            scope: 'editor',
            edgesTo: ['bill-detail', 'bills'],
          },
        },
      },
      {
        path: 'bills/:id',
        loadComponent: () =>
          import('./pages/bill-detail/bill-detail.component').then((m) => m.BillDetailComponent),
        data: {
          flow: {
            flowId: 'bill-detail',
            node: 'bill-detail',
            label: 'Bill detail',
            scope: 'all',
            edgesTo: ['bills', 'bill-edit', 'legislator-detail', 'conflicts'],
          },
        },
      },

      // ---- Legislators (public) ----
      {
        path: 'legislators',
        loadComponent: () =>
          import('./pages/legislators-list/legislators-list.component').then(
            (m) => m.LegislatorsListComponent,
          ),
        data: {
          flow: {
            flowId: 'legislators',
            node: 'legislators',
            showInNavbar: true,
            label: 'Legislators',
            scope: 'all',
            edgesTo: ['legislator-detail', 'legislator-new', 'bills'],
          },
        },
      },
      {
        path: 'legislators/new',
        loadComponent: () =>
          import('./pages/legislator-form/legislator-form.component').then(
            (m) => m.LegislatorFormComponent,
          ),
        canActivate: [authGuard],
        data: {
          flow: {
            flowId: 'legislator-new',
            node: 'legislator-new',
            label: 'New legislator',
            scope: 'editor',
            edgesTo: ['legislators'],
          },
        },
      },
      {
        path: 'legislators/:id/edit',
        loadComponent: () =>
          import('./pages/legislator-form/legislator-form.component').then(
            (m) => m.LegislatorFormComponent,
          ),
        canActivate: [authGuard],
        data: {
          flow: {
            flowId: 'legislator-edit',
            node: 'legislator-edit',
            label: 'Edit legislator',
            scope: 'editor',
            edgesTo: ['legislator-detail', 'legislators'],
          },
        },
      },
      {
        path: 'legislators/:id',
        loadComponent: () =>
          import('./pages/legislator-detail/legislator-detail.component').then(
            (m) => m.LegislatorDetailComponent,
          ),
        data: {
          flow: {
            flowId: 'legislator-detail',
            node: 'legislator-detail',
            label: 'Legislator detail',
            scope: 'all',
            edgesTo: ['legislators', 'legislator-edit', 'bill-detail'],
          },
        },
      },

      // ---- Conflicts overview (public) ----
      {
        path: 'conflicts',
        loadComponent: () =>
          import('./pages/conflicts/conflicts.component').then((m) => m.ConflictsComponent),
        data: {
          flow: {
            flowId: 'conflicts',
            node: 'conflicts',
            showInNavbar: true,
            label: 'Conflicts',
            scope: 'all',
            edgesTo: ['bill-detail', 'bills'],
          },
        },
      },

      // ---- Editor login ----
      {
        path: 'login',
        loadComponent: () =>
          import('./pages/login/login.component').then((m) => m.LoginComponent),
        data: {
          flow: { flowId: 'login', node: 'login', entry: true, label: 'Editor login', edgesTo: ['bills'] },
        },
      },
    ],
  },

  { path: '**', redirectTo: 'bills' },
] satisfies FlowRoute[]) as Routes;
